import React from 'react';
import { useApp } from '../../context/AppContext';
import { Users, ShieldOff, Shield } from 'lucide-react';

export default function UsersAdmin() {
  const { users, toggleUserBlock, currentUser } = useApp();

  const clients = users.filter(u => u.role === 'cliente');

  return (
    <div>
      <div className="page-header">
        <div><h1>Usuarios</h1><p>{clients.length} clientes registrados</p></div>
      </div>

      <div className="card">
        <div className="table-container">
          {clients.length === 0 ? (
            <div className="empty-state"><Users size={40} /><p>No hay usuarios registrados</p></div>
          ) : (
            <table>
              <thead><tr><th>Usuario</th><th>Correo</th><th>Fecha de registro</th><th>Estado</th><th>Acciones</th></tr></thead>
              <tbody>
                {clients.map(u => (
                  <tr key={u.id}>
                    <td>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <div style={{ width: 34, height: 34, borderRadius: '50%', background: 'linear-gradient(135deg, var(--pink-300), var(--pink-500))', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: '0.9rem', flexShrink: 0 }}>
                          {u.name[0]}
                        </div>
                        <span style={{ fontWeight: 600, fontSize: '0.9rem' }}>{u.name}</span>
                      </div>
                    </td>
                    <td style={{ color: 'var(--gray-400)', fontSize: '0.88rem' }}>{u.email}</td>
                    <td style={{ color: 'var(--gray-400)', fontSize: '0.82rem' }}>{u.joinDate}</td>
                    <td>
                      <span className={`badge ${u.status === 'activo' ? 'badge-success' : 'badge-danger'}`}>
                        {u.status}
                      </span>
                    </td>
                    <td>
                      {u.id !== currentUser?.id && (
                        <button
                          className={`btn btn-sm ${u.status === 'activo' ? 'btn-danger' : 'btn-success'}`}
                          onClick={() => toggleUserBlock(u.id)}
                        >
                          {u.status === 'activo' ? <><ShieldOff size={13} /> Bloquear</> : <><Shield size={13} /> Desbloquear</>}
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}
